'use server';

/**
 * @fileOverview Analyzes a fundus image to classify disease severity and provide explanations using XAI.
 *
 * - analyzeFundusImageAndExplain - Analyzes the fundus image and provides a disease classification, confidence score,
 *   explanation, and XAI heatmap.
 * - AnalyzeFundusImageAndExplainInput - The input type for the analyzeFundusImageAndExplain function.
 * - AnalyzeFundusImageAndExplainOutput - The return type for the analyzeFundusImageAndExplain function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';

const AnalyzeFundusImageAndExplainInputSchema = z.object({
  fundusImageDataUri: z
    .string()
    .describe(
      "A fundus image as a data URI that must include a MIME type and use Base64 encoding. Expected format: 'data:<mimetype>;base64,<encoded_data>'."
    ),
});
export type AnalyzeFundusImageAndExplainInput = z.infer<
  typeof AnalyzeFundusImageAndExplainInputSchema
>;

const AnalyzeFundusImageAndExplainOutputSchema = z.object({
  label: z.enum(['Yok', 'Hafif', 'Orta', 'Ciddi', 'Proliferatif']).describe('Disease classification label.'),
  confidence: z.number().describe('Confidence score of the classification (0-1).'),
  explanation: z.string().describe('A short explanation of the model\'s decision.'),
  heatmapDataUri: z
    .string()
    .describe(
      'A data URI containing the XAI heatmap overlay image. Expected format: \'data:<mimetype>;base64,<encoded_data>\'.'
    ),
});
export type AnalyzeFundusImageAndExplainOutput = z.infer<
  typeof AnalyzeFundusImageAndExplainOutputSchema
>;

export async function analyzeFundusImageAndExplain(
  input: AnalyzeFundusImageAndExplainInput
): Promise<AnalyzeFundusImageAndExplainOutput> {
  // To demonstrate the UI, we'll return a mock result.
  // In a real application, you would call the Genkit flow.
  // return analyzeFundusImageAndExplainFlow(input);
  
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 1500));

  return {
    label: 'Orta',
    confidence: 0.82,
    explanation: 'Görüntüde mikroanevrizmalar ve birkaç sert eksüda tespit edildi. Bu bulgular orta düzeyde diyabetik retinopatiyi göstermektedir. Optik disk ve makula bölgesi nispeten normal sınırlardadır.',
    heatmapDataUri: 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=', // transparent pixel to prevent breaking image, will be replaced by a real heatmap image
  };
}


const analyzeFundusImageAndExplainPrompt = ai.definePrompt({
  name: 'analyzeFundusImageAndExplainPrompt',
  input: {schema: AnalyzeFundusImageAndExplainInputSchema},
  output: {schema: AnalyzeFundusImageAndExplainOutputSchema},
  prompt: `You are an AI model specializing in analyzing fundus images to detect and classify diabetic retinopathy.
  Given a fundus image, classify the severity of the disease and provide a confidence score.
  Also, provide a short explanation of the factors that led to the classification.
  You must also generate an XAI heatmap highlighting the areas of the image that contributed most to the classification.

  The classification should be one of the following Turkish labels: Yok, Hafif, Orta, Ciddi, Proliferatif.

  Analyze the fundus image provided here: {{media url=fundusImageDataUri}}

  Ensure the output is in the correct JSON format.`,
  config: {
    safetySettings: [
      {category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH'},
      {category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE'},
      {category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE'},
      {category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_LOW_AND_ABOVE'},
    ],
  },
});

const analyzeFundusImageAndExplainFlow = ai.defineFlow(
  {
    name: 'analyzeFundusImageAndExplainFlow',
    inputSchema: AnalyzeFundusImageAndExplainInputSchema,
    outputSchema: AnalyzeFundusImageAndExplainOutputSchema,
  },
  async input => {
    const {output} = await analyzeFundusImageAndExplainPrompt(input);
    
    // In a real scenario, the GenAI model would also generate the heatmap.
    // For now, we are returning a placeholder.
    const mockHeatmap = 'data:image/png;base64,';

    if (output) {
      output.heatmapDataUri = mockHeatmap;
      return output;
    }

    return {
      label: 'Hafif',
      confidence: 0.75,
      explanation: 'Model, görüntüde hafif düzeyde diyabetik retinopati belirtileri tespit etti.',
      heatmapDataUri: mockHeatmap,
    };
  }
);
